"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["968"],{8927(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/ko/blog/welcome","source":"@site/i18n/ko/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 Wiki\uC5D0 \uC624\uC2E0 \uAC83\uC744 \uD658\uC601\uD569\uB2C8\uB2E4","description":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 Wiki\uC5D0 \uC624\uC2E0 \uAC83\uC744 \uD658\uC601\uD569\uB2C8\uB2E4! \uC81C\uD488 \uBB38\uC11C, \uAE30\uC220 \uC194\uB8E8\uC158, \uC5C5\uACC4 \uB274\uC2A4 \uBC0F \uD68C\uC0AC \uC18C\uC2DD\uC744 \uD55C\uB370 \uBAA8\uC740 \uACF5\uC2DD \uC9C0\uC2DD \uBCA0\uC774\uC2A4\uC785\uB2C8\uB2E4.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0","permalink":"/heiman-wiki-public/ko/blog/tags/heiman","description":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 \uB274\uC2A4 \uBC0F \uC5C5\uB370\uC774\uD2B8"}],"readingTime":0.56,"hasTruncateMarker":true,"authors":[{"name":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/ko/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 Wiki\uC5D0 \uC624\uC2E0 \uAC83\uC744 \uD658\uC601\uD569\uB2C8\uB2E4","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"\uD558\uC774\uB9CC Matter \uC2A4\uB9C8\uD2B8 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uACF5\uC2DD \uCD9C\uC2DC","permalink":"/heiman-wiki-public/ko/blog/mdx-blog-post"}},"content":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 Wiki\uC5D0 \uC624\uC2E0 \uAC83\uC744 \uD658\uC601\uD569\uB2C8\uB2E4! \uC81C\uD488 \uBB38\uC11C, \uAE30\uC220 \uC194\uB8E8\uC158, \uC5C5\uACC4 \uB274\uC2A4 \uBC0F \uD68C\uC0AC \uC18C\uC2DD\uC744 \uD55C\uB370 \uBAA8\uC740 \uACF5\uC2DD \uC9C0\uC2DD \uBCA0\uC774\uC2A4\uC785\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uC774 \uC0AC\uC774\uD2B8 \uC18C\uAC1C\\n\\n\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 Wiki\uB294 \uD30C\uD2B8\uB108, \uAC1C\uBC1C\uC790 \uBC0F \uACE0\uAC1D\uC5D0\uAC8C \uC6D0\uC2A4\uD1B1 \uAE30\uC220 \uB9AC\uC18C\uC2A4\uB97C \uC81C\uACF5\uD558\uAE30 \uC704\uD574 \uB9C8\uB828\uB418\uC5C8\uC2B5\uB2C8\uB2E4:\\n\\n- **\uC81C\uD488** \u2014 \uC2A4\uB9C8\uD2B8 \uD654\uC7AC \uC548\uC804, \uC2A4\uB9C8\uD2B8 \uAC00\uC2A4 \uC548\uC804, \uC2A4\uB9C8\uD2B8 \uB178\uC778 \uCF00\uC5B4, \uC2A4\uB9C8\uD2B8 \uC13C\uC11C\\n- **\uC194\uB8E8\uC158** \u2014 \uC5C5\uACC4 \uC218\uC900\uC758 \uC2A4\uB9C8\uD2B8 \uBCF4\uC548 \uC194\uB8E8\uC158\\n- **\uAE30\uC220 \uBB38\uC11C** \u2014 API \uD1B5\uD569 \uAC00\uC774\uB4DC, SDK \uC0AC\uC6A9\uBC95, \uC124\uCE58 \uC124\uBA85\uC11C\\n- **\uC5C5\uACC4 \uC778\uC0AC\uC774\uD2B8** \u2014 \uC2A4\uB9C8\uD2B8 \uBCF4\uC548 \uB3D9\uD5A5 \uBC0F \uC815\uCC45 \uD574\uC124\\n\\n## \uBE60\uB978 \uD0D0\uC0C9\\n\\n- [\uC81C\uD488 \uBC0F \uC194\uB8E8\uC158](/docs/tutorial-basics/create-a-page) \uC0B4\uD3B4\uBCF4\uAE30\\n- [\uD68C\uC0AC \uC18C\uAC1C](/docs/intro)\uC5D0\uC11C \uD558\uC774\uB9CC\uC758 \uC774\uC57C\uAE30 \uC77D\uAE30\\n- [\uD558\uC774\uB9CC \uACF5\uC2DD \uC0AC\uC774\uD2B8](https://www.heiman.com.cn) \uBC29\uBB38\uD558\uAE30\\n\\n\uBB38\uC758\uC0AC\uD56D\uC774 \uC788\uC73C\uC2DC\uBA74 \uD56B\uB77C\uC778 **400-8959-500**\uC73C\uB85C \uC804\uD654\uD558\uAC70\uB098 \uC628\uB77C\uC778 \uC9C0\uC6D0\uC5D0 \uBB38\uC758\uD574 \uC8FC\uC2ED\uC2DC\uC624."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/ko/blog/mdx-blog-post","source":"@site/i18n/ko/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"\uD558\uC774\uB9CC Matter \uC2A4\uB9C8\uD2B8 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uACF5\uC2DD \uCD9C\uC2DC","description":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0\uC758 \uCC28\uC138\uB300 Matter \uD504\uB85C\uD1A0\uCF5C \uC2A4\uB9C8\uD2B8 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 HS1SA-M\uC774 \uACF5\uC2DD \uCD9C\uC2DC\uB418\uC5C8\uC2B5\uB2C8\uB2E4 \u2014 \uC5C5\uACC4 \uCD5C\uCD08\uB85C Matter 1.2 \uC778\uC99D\uC744 \uBC1B\uC740 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uC911 \uD558\uB098\uC785\uB2C8\uB2E4.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/ko/blog/tags/matter","description":"Matter \uD504\uB85C\uD1A0\uCF5C \uAD00\uB828 \uCF58\uD150\uCE20"},{"inline":false,"label":"\uC2A4\uB9C8\uD2B8 \uD654\uC7AC \uC548\uC804","permalink":"/heiman-wiki-public/ko/blog/tags/smart-fire","description":"\uC2A4\uB9C8\uD2B8 \uD654\uC7AC \uC548\uC804 \uC81C\uD488 \uBC0F \uC194\uB8E8\uC158"}],"readingTime":0.6,"hasTruncateMarker":true,"authors":[{"name":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/ko/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"\uD558\uC774\uB9CC Matter \uC2A4\uB9C8\uD2B8 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uACF5\uC2DD \uCD9C\uC2DC","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 Wiki\uC5D0 \uC624\uC2E0 \uAC83\uC744 \uD658\uC601\uD569\uB2C8\uB2E4","permalink":"/heiman-wiki-public/ko/blog/welcome"},"nextItem":{"title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 \uC8FC\uC694 \uC774\uC815\uD45C","permalink":"/heiman-wiki-public/ko/blog/long-blog-post"}},"content":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0\uC758 \uCC28\uC138\uB300 Matter \uD504\uB85C\uD1A0\uCF5C \uC2A4\uB9C8\uD2B8 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 HS1SA-M\uC774 \uACF5\uC2DD \uCD9C\uC2DC\uB418\uC5C8\uC2B5\uB2C8\uB2E4 \u2014 \uC5C5\uACC4 \uCD5C\uCD08\uB85C Matter 1.2 \uC778\uC99D\uC744 \uBC1B\uC740 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uC911 \uD558\uB098\uC785\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nHS1SA-M\uC740 Apple HomeKit, Amazon Alexa, Google Home \uBC0F Samsung SmartThings \u2014 4\uB300 \uC2A4\uB9C8\uD2B8 \uD648 \uC5D0\uCF54\uC2DC\uC2A4\uD15C\uC744 \uC9C0\uC6D0\uD569\uB2C8\uB2E4.\\n\\n:::\\n\\n## \uC8FC\uC694 \uAE30\uB2A5\\n\\n- **Matter 1.2 \uC778\uC99D** \u2014 \uD06C\uB85C\uC2A4 \uBE0C\uB79C\uB4DC, \uD06C\uB85C\uC2A4 \uC5D0\uCF54\uC2DC\uC2A4\uD15C \uC0C1\uD638 \uC6B4\uC6A9\uC131\\n- **\uAD11\uC804\uC2DD \uC5F0\uAE30 \uAC10\uC9C0** \u2014 \uB2E4\uC591\uD55C \uD654\uC7AC \uC5F0\uAE30 \uC720\uD615\uC5D0 \uC2E0\uC18D \uB300\uC751\\n- **\uC74C\uC131 \uACBD\uBCF4** \u2014 \uC5EC\uB7EC \uC5B8\uC5B4 \uC635\uC158, \uBA85\uD655\uD55C \uC704\uD5D8 \uC54C\uB9BC\\n- **\uC790\uCCB4 \uD14C\uC2A4\uD2B8 \uAE30\uB2A5** \u2014 \uC815\uAE30 \uC790\uCCB4 \uC810\uAC80\uC73C\uB85C \uC815\uC0C1 \uC791\uB3D9 \uBCF4\uC7A5\\n- **\uC6D0\uACA9 \uC54C\uB9BC** \u2014 \uD734\uB300\uD3F0 APP\uC73C\uB85C \uC2E4\uC2DC\uAC04 \uD478\uC2DC \uC54C\uB9BC\\n\\n## \uD638\uD658\uC131\\n\\nHS1SA-M\uC740 \uCD94\uAC00 \uAC8C\uC774\uD2B8\uC6E8\uC774 \uC5C6\uC774 \uC8FC\uC694 \uC2A4\uB9C8\uD2B8 \uD648 \uD50C\uB7AB\uD3FC\uACFC \uC6D0\uD65C\uD558\uAC8C \uD1B5\uD569\uB429\uB2C8\uB2E4 \u2014 \uD734\uB300\uD3F0\uC5D0\uC11C \uC9C1\uC811 \uBAA8\uB450 \uAD00\uB9AC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n[\uC81C\uD488](/docs/tutorial-basics/create-a-page) \uD398\uC774\uC9C0\uB97C \uBC29\uBB38\uD558\uC5EC \uB354 \uC790\uC138\uD788 \uC54C\uC544\uBCF4\uC138\uC694."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/ko/blog/long-blog-post","source":"@site/i18n/ko/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 \uC8FC\uC694 \uC774\uC815\uD45C","description":"2005\uB144 \uC124\uB9BD \uC774\uD6C4 \uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0\uB294 20\uB144\uC774 \uB118\uB294 \uC5EC\uC815\uC744 \uAC78\uC5B4\uC654\uC2B5\uB2C8\uB2E4. \uC774 \uAE00\uC740 \uD558\uC774\uB9CC\uC758 \uC8FC\uC694 \uC774\uC815\uD45C\uB97C \uB418\uB3CC\uC544\uBD05\uB2C8\uB2E4.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0","permalink":"/heiman-wiki-public/ko/blog/tags/heiman","description":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 \uB274\uC2A4 \uBC0F \uC5C5\uB370\uC774\uD2B8"}],"readingTime":1.06,"hasTruncateMarker":true,"authors":[{"name":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/ko/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 \uC8FC\uC694 \uC774\uC815\uD45C","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"\uD558\uC774\uB9CC Matter \uC2A4\uB9C8\uD2B8 \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uACF5\uC2DD \uCD9C\uC2DC","permalink":"/heiman-wiki-public/ko/blog/mdx-blog-post"},"nextItem":{"title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0, \uAD6D\uAC00 \\"\uC791\uC740 \uAC70\uC778\\" \uAE30\uC5C5\uC73C\uB85C \uC778\uC815\uBC1B\uB2E4","permalink":"/heiman-wiki-public/ko/blog/first-blog-post"}},"content":"2005\uB144 \uC124\uB9BD \uC774\uD6C4 \uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0\uB294 20\uB144\uC774 \uB118\uB294 \uC5EC\uC815\uC744 \uAC78\uC5B4\uC654\uC2B5\uB2C8\uB2E4. \uC774 \uAE00\uC740 \uD558\uC774\uB9CC\uC758 \uC8FC\uC694 \uC774\uC815\uD45C\uB97C \uB418\uB3CC\uC544\uBD05\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## 2005\uB144 - \uD68C\uC0AC \uC124\uB9BD\\n\\nShenzhen Heiman Technology Co., Ltd.\uAC00 \uACF5\uC2DD \uC124\uB9BD\uB418\uC5B4 \uBCF4\uC548 \uC13C\uC11C \uBD84\uC57C\uC5D0 \uC9C4\uCD9C\uD588\uC2B5\uB2C8\uB2E4.\\n\\n## 2006\uB144 - \uAD6D\uC81C\uC801 \uC2DC\uC791\\n\\n\uC5EC\uB7EC \uC81C\uD488\uC774 EU CE \uC778\uC99D\uC744 \uD1B5\uACFC\uD558\uACE0 China Mobile\uACFC \uD30C\uD2B8\uB108\uC2ED\uC744 \uCCB4\uACB0\uD588\uC2B5\uB2C8\uB2E4.\\n\\n## 2011\uB144 - \uAD6D\uC81C \uC778\uC99D \uB3CC\uD30C\\n\\n\uC5EC\uB7EC \uC81C\uD488\uC774 EU EN54-7 \uBC0F EN14604 \uC778\uC99D\uC744 \uD1B5\uACFC\uD558\uC5EC \uAD6D\uC81C \uD488\uC9C8 \uAE30\uC900\uC5D0 \uB3C4\uB2EC\uD588\uC2B5\uB2C8\uB2E4.\\n\\n## 2012\uB144 - \uC2A4\uB9C8\uD2B8 \uD648 \uC804\uD658\\n\\n\uC2A4\uB9C8\uD2B8 \uD648 \uD504\uB85C\uC81D\uD2B8\uAC00 \uC804\uBA74\uC801\uC73C\uB85C \uC2DC\uC791\uB418\uC5B4 \uD558\uC774\uB9CC\uC774 \uC2A4\uB9C8\uD2B8 \uD648 \uC81C\uD488\uC758 R&D, \uC0DD\uC0B0 \uBC0F \uD310\uB9E4\uB97C \uC804\uBB38\uC73C\uB85C \uD558\uB294 \uAE30\uC5C5\uC73C\uB85C \uC804\uD658\uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n## 2017\uB144 - \uC8FC\uC694 \uB3CC\uD30C\uAD6C\\n\\n- \uC911\uAD6D \uCD5C\uCD08\uC758 NB-IoT \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uAC1C\uBC1C\\n- Red Dot \uB514\uC790\uC778 \uC5B4\uC6CC\uB4DC 2\uAC1C \uC218\uC0C1\\n- MFi \uC778\uC99D \uD1B5\uACFC, Apple \uC81C\uC870\uC5C5\uCCB4 \uC790\uACA9 \uD68D\uB4DD\\n\\n## 2020\uB144 - \uC790\uBCF8 \uD22C\uC790 \uC720\uCE58\\n\\nShenzhen\u9AD8\u65B0\u6295 Group\uACFC \uC2DC\uB9AC\uC988 A \uD22C\uC790 \uC720\uCE58 \uC644\uB8CC, \\"\uAD11\uB3D9\uC131 \uC804\uBB38\xb7\uC2E0\uD615 \uC911\uC18C\uAE30\uC5C5\\"\uC73C\uB85C \uC778\uC815\uBC1B\uC74C.\\n\\n## 2022\uB144 - \uAD6D\uAC00\uC801 \uC778\uC815\\n\\n\uAD6D\uAC00 \uC804\uBB38\xb7\uC2E0\uD615 \\"\uC791\uC740 \uAC70\uC778\\" \uAE30\uC5C5\uC73C\uB85C \uC778\uC815\uBC1B\uC74C. K1 \uC2DC\uB9AC\uC988\uAC00 Red Dot \uB514\uC790\uC778 \uC5B4\uC6CC\uB4DC \uC218\uC0C1.\\n\\n## 2023\uB144 - \uAD6D\uC81C \uD45C\uC900 \uC120\uB3C4\\n\\n\uD558\uC774\uB9CC \uD14C\uC2A4\uD2B8 \uC5F0\uAD6C\uC18C\uAC00 \uACF5\uC2DD\uC801\uC73C\uB85C CNAS \uC778\uC99D\uC744 \uD1B5\uACFC\uD568. \uC5F0\uAE30 \uAC10\uC9C0\uAE30 \uBC0F CO \uACBD\uBCF4\uAE30\uAC00 \uC5C5\uACC4 \uCD5C\uCD08\uB85C Matter 1.2 \uC778\uC99D\uC744 \uD68D\uB4DD\uD568.\\n\\n## 2024\uB144 - \uD604\uC7AC\\n\\n\uC9C0\uC18D\uC801\uC778 \uD601\uC2E0\uC744 \uC774\uC5B4\uAC00\uBA70 \uC2A4\uB9C8\uD2B8 \uD654\uC7AC \uC548\uC804, \uC2A4\uB9C8\uD2B8 \uAC00\uC2A4 \uC548\uC804, \uC2A4\uB9C8\uD2B8 \uB178\uC778 \uCF00\uC5B4 \uBC0F \uC2A4\uB9C8\uD2B8 \uC13C\uC11C\uC5D0 \uB300\uD55C \uB178\uB825\uC744 \uAC15\uD654\uD558\uC5EC \uC804 \uC138\uACC4 100\uAC1C \uC774\uC0C1\uC758 \uAD6D\uAC00 \uACE0\uAC1D\uC5D0\uAC8C\u4F18\u8D28(\uACE0\uD488\uC9C8) \uC81C\uD488\uACFC \uC11C\uBE44\uC2A4\uB97C \uC81C\uACF5\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/ko/blog/first-blog-post","source":"@site/i18n/ko/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0, \uAD6D\uAC00 \\"\uC791\uC740 \uAC70\uC778\\" \uAE30\uC5C5\uC73C\uB85C \uC778\uC815\uBC1B\uB2E4","description":"2022\uB144, \uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0\uB294 \uC2A4\uB9C8\uD2B8 \uC13C\uC11C \uBD84\uC57C\uC5D0\uC11C\uC758 \uAE4A\uC740 \uAE30\uC220 \uCD95\uC801\uACFC \uD601\uC2E0\uC744 \uC778\uC815\uBC1B\uC544 \uAD6D\uAC00 \uC804\uBB38\xb7\uC2E0\uD615 \\"\uC791\uC740 \uAC70\uC778\\" \uAE30\uC5C5\uC73C\uB85C \uACF5\uC2DD \uC778\uC815\uB418\uC5C8\uC2B5\uB2C8\uB2E4.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0","permalink":"/heiman-wiki-public/ko/blog/tags/heiman","description":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 \uB274\uC2A4 \uBC0F \uC5C5\uB370\uC774\uD2B8"}],"readingTime":0.37,"hasTruncateMarker":true,"authors":[{"name":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/ko/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0, \uAD6D\uAC00 \\"\uC791\uC740 \uAC70\uC778\\" \uAE30\uC5C5\uC73C\uB85C \uC778\uC815\uBC1B\uB2E4","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"\uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0 \uC8FC\uC694 \uC774\uC815\uD45C","permalink":"/heiman-wiki-public/ko/blog/long-blog-post"}},"content":"2022\uB144, \uD558\uC774\uB9CC \uD14C\uD06C\uB180\uB85C\uC9C0\uB294 \uC2A4\uB9C8\uD2B8 \uC13C\uC11C \uBD84\uC57C\uC5D0\uC11C\uC758 \uAE4A\uC740 \uAE30\uC220 \uCD95\uC801\uACFC \uD601\uC2E0\uC744 \uC778\uC815\uBC1B\uC544 \uAD6D\uAC00 \uC804\uBB38\xb7\uC2E0\uD615 \\"\uC791\uC740 \uAC70\uC778\\" \uAE30\uC5C5\uC73C\uB85C \uACF5\uC2DD \uC778\uC815\uB418\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n\uC774\uBC88 \uAD6D\uAC00\uC801 \uCC28\uC6D0\uC758 \uC778\uC815\uC740 \uC804\uBB38\uC131, \uC815\uBC00\uC131, \uCC28\uBCC4\uD654 \uBC0F \uD601\uC2E0 \uBD84\uC57C\uC5D0\uC11C \uD558\uC774\uB9CC\uC758 \uC6B0\uC218\uC131\uC744 \uC785\uC99D\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4. \uD558\uC774\uB9CC\uC740 \uC2A4\uB9C8\uD2B8 \uD654\uC7AC \uC548\uC804, \uC2A4\uB9C8\uD2B8 \uAC00\uC2A4 \uC548\uC804, \uC2A4\uB9C8\uD2B8 \uB178\uC778 \uCF00\uC5B4 \uBC0F \uC2A4\uB9C8\uD2B8 \uC13C\uC11C\uC5D0 \uB300\uD55C \uB178\uB825\uC744 \uACC4\uC18D \uC2EC\uD654\uD558\uC5EC \uACE0\uAC1D\uC5D0\uAC8C \uC9C0\uC18D\uC801\uC73C\uB85C \uACE0\uD488\uC9C8 \uC81C\uD488\uACFC \uC11C\uBE44\uC2A4\uB97C \uC81C\uACF5\uD560 \uAC83\uC785\uB2C8\uB2E4.\\n\\n\uD558\uC774\uB9CC\uC740 \uC774\uC804\uC5D0 \uAD6D\uAC00 \uCCA8\uB2E8 \uAE30\uC220 \uAE30\uC5C5 \uBC0F \uAD11\uB3D9\uC131 \uC804\uBB38\xb7\uC2E0\uD615 \uC911\uC18C\uAE30\uC5C5\uC73C\uB85C \uC778\uC815\uBC1B\uC740 \uBC14 \uC788\uC2B5\uB2C8\uB2E4."}]}}')}}]);